"""Probe: does a state trigger with `not_from: [unknown, unavailable]` fire
when the entity *appears* with a restored value (old_state=None)?"""

from __future__ import annotations

import pathlib
from unittest.mock import patch

import pytest
from pytest_homeassistant_custom_component.common import (
    MockConfigEntry,
    async_mock_service,
    mock_restore_cache_with_extra_data,
)

from homeassistant.components import automation
from homeassistant.components.blueprint import models
from homeassistant.const import ATTR_FRIENDLY_NAME
from homeassistant.core import HomeAssistant, State, callback
from homeassistant.setup import async_setup_component
from homeassistant.util import yaml as yaml_util

from custom_components.lock_code_manager.const import DOMAIN

from .common import BASE_CONFIG, LOCK_1_ENTITY_ID, SLOT_1_EVENT_ENTITY


@pytest.mark.asyncio
async def test_probe_trigger_from_none(
    hass: HomeAssistant, mock_lock_config_entry
) -> None:
    """Restore cache primed BEFORE LCM, listener primed BEFORE entity appears."""
    restored_ts = "2026-01-01T12:00:00.000+00:00"
    mock_restore_cache_with_extra_data(
        hass,
        [
            (
                State(
                    SLOT_1_EVENT_ENTITY,
                    restored_ts,
                    {
                        "event_type": LOCK_1_ENTITY_ID,
                        "code_slot": 1,
                        "code_slot_name": "test1",
                        ATTR_FRIENDLY_NAME: "Code slot 1",
                    },
                ),
                {
                    "last_event_type": LOCK_1_ENTITY_ID,
                    "last_event_attributes": {
                        "code_slot": 1,
                        "code_slot_name": "test1",
                    },
                },
            )
        ],
    )

    captured = async_mock_service(hass, "test", "captured")
    transitions: list[tuple[str | None, str | None]] = []

    @callback
    def listener(event):
        if event.data.get("entity_id") != SLOT_1_EVENT_ENTITY:
            return
        old = event.data.get("old_state")
        new = event.data.get("new_state")
        transitions.append(
            (
                None if old is None else old.state,
                None if new is None else new.state,
            )
        )

    hass.bus.async_listen("state_changed", listener)

    blueprint_path = "slot_usage_notifier.yaml"
    data_path = (
        pathlib.Path(__file__).resolve().parent.parent
        / "blueprints"
        / "automation"
        / "lock_code_manager"
        / blueprint_path
    )
    orig_load = models.DomainBlueprints._load_blueprint

    @callback
    def mock_load(self, path):
        if path != blueprint_path:
            return orig_load(self, path)
        return models.Blueprint(
            yaml_util.load_yaml(data_path),
            expected_domain=self.domain,
            path=path,
            schema=automation.config.AUTOMATION_BLUEPRINT_SCHEMA,
        )

    with patch(
        "homeassistant.components.blueprint.models.DomainBlueprints._load_blueprint",
        mock_load,
    ):
        assert await async_setup_component(
            hass,
            "automation",
            {
                "automation": {
                    "use_blueprint": {
                        "path": blueprint_path,
                        "input": {
                            "event_entity": [SLOT_1_EVENT_ENTITY],
                            "notify_actions": [{"service": "test.captured"}],
                        },
                    }
                }
            },
        )
    await hass.async_block_till_done()

    print(f"\n>>> Captured BEFORE LCM setup: {len(captured)}")
    print(f">>> Transitions BEFORE LCM setup: {transitions}")

    config_entry = MockConfigEntry(
        domain=DOMAIN, data=BASE_CONFIG, unique_id="Mock Title"
    )
    config_entry.add_to_hass(hass)
    await hass.config_entries.async_setup(config_entry.entry_id)
    await hass.async_block_till_done()

    print(f">>> Captured AFTER LCM setup: {len(captured)}")
    print(f">>> Transitions AFTER LCM setup: {transitions}")

